+// ---------------------------------------------------------------------------
+// 6-8: TtyControlFrame transcript variant serde round-trips
+// ---------------------------------------------------------------------------
+
+#[test]
+fn transcript_partial_serde_round_trip() {
+    let frame = TtyControlFrame::TranscriptPartial {
+        seq: 42,
+        window_id: 7,
